use std::collections::{BTreeMap, HashMap};
use smallvec::SmallVec;

pub fn parse_http_request(request: &str) -> (SmallVec<[(&str, &str); 8]>, HashMap<&str, &str>, Vec<&str>, BTreeMap<&str, &str>) {
    let mut common_headers = SmallVec::new();
    let mut all_headers = HashMap::new();
    let mut raw_header_lines = Vec::new();
    let mut cookies = BTreeMap::new();

    let mut lines = request.lines();

    // Skip the request line
    if let Some(_) = lines.next() {
        for line in lines {
            if line.trim().is_empty() {
                break; // End of headers
            }
            raw_header_lines.push(line);

            if let Some((name, value)) = line.split_once(':') {
                let name = name.trim();
                let value = value.trim();

                // Store in all headers
                all_headers.insert(name, value);

                // Store common headers in SmallVec
                match name {
                    "Host" | "User-Agent" | "Accept" | "Accept-Language" | "Accept-Encoding" 
                    | "Connection" | "Referer" | "Content-Type" | "Content-Length" => {
                        common_headers.push((name, value));
                    }
                    "Cookie" => {
                        // Parse cookies
                        for cookie in value.split(';') {
                            if let Some((cookie_name, cookie_value)) = cookie.split_once('=') {
                                cookies.insert(cookie_name.trim(), cookie_value.trim());
                            }
                        }
                    }
                    _ => {}
                }
            }
        }
    }

    (common_headers, all_headers, raw_header_lines, cookies)
}
