func calculate_response_stats(responseTimes []float64) (float64, float64, float64, int, error) {
	if len(responseTimes) == 0 {
		return 0, 0, 0, 0, errors.New("input slice is empty")
	}

	// Calculate mean
	sum := 0.0
	for _, v := range responseTimes {
		sum += v
	}
	mean := sum / float64(len(responseTimes))

	// Calculate median
	sortedTimes := make([]float64, len(responseTimes))
	copy(sortedTimes, responseTimes)
	sort.Float64s(sortedTimes)
	var median float64
	n := len(sortedTimes)
	if n%2 == 0 {
		median = (sortedTimes[n/2-1] + sortedTimes[n/2]) / 2
	} else {
		median = sortedTimes[n/2]
	}

	// Calculate 95th percentile
	index := int(float64(len(sortedTimes)) * 0.95)
	var percentile95 float64
	if index >= len(sortedTimes) {
		percentile95 = sortedTimes[len(sortedTimes)-1]
	} else {
		percentile95 = sortedTimes[index]
	}

	return mean, median, percentile95, len(responseTimes), nil
}
