		return 0.0, 0.0
	}

	sum := 0.0
	for _, temp := range temperatures {
		sum += temp
	}
	avg := sum / n

	variance := 0.0
	for _, temp := range temperatures {
		diff := temp - avg
		variance += diff * diff
	}
	variance /= n
