use arrayvec::ArrayVec;

#[derive(Debug)]
struct Transaction {
    account_id: String,
    amount: f64,
    transaction_type: TransactionType,
}

#[derive(Debug)]
enum TransactionType {
    Deposit,
    Withdrawal,
}

#[derive(Debug)]
struct ProcessedTransaction {
    transaction: Transaction,
    status: TransactionStatus,
}

#[derive(Debug)]
enum TransactionStatus {
    Successful,
    Failed,
}

fn manage_account_transactions(transactions: Vec<Transaction>) -> (
    VecDeque<Transaction>,
    BTreeMap<String, f64>,
    BTreeSet<String>,
    ArrayVec<ProcessedTransaction, 5>,
) {
    let mut pending_failed = VecDeque::new();
    let mut account_balances = BTreeMap::new();
    let mut flagged_accounts = BTreeSet::new();
    let mut last_five = ArrayVec::new();

    for transaction in transactions {
        let account_id = transaction.account_id.clone();
        let balance = account_balances.entry(account_id.clone()).or_insert(0.0);

        let status = match transaction.transaction_type {
            TransactionType::Deposit => {
                *balance += transaction.amount;
                TransactionStatus::Successful
            }
            TransactionType::Withdrawal => {
                if *balance >= transaction.amount {
                    *balance -= transaction.amount;
                    if transaction.amount > 1000.0 { // Example threshold for suspicious activity
                        flagged_accounts.insert(account_id.clone());
                    }
                    TransactionStatus::Successful
                } else {
                    pending_failed.push_back(transaction);
                    TransactionStatus::Failed
                }
            }
        };

        let processed = ProcessedTransaction { transaction, status };
        if last_five.is_full() {
            last_five.remove(0);
        }
        last_five.push(processed);
    }

    (pending_failed, account_balances, flagged_accounts, last_five)
}
